#include <stdio.h>
#include <string.h>

int main(){
    int T; if(scanf("%d",&T)!=1) return 0; getchar(); // consume newline after T
    for(int tc=0; tc<T; ++tc){
        char name[101];
        if(!fgets(name, sizeof(name), stdin)) break;
        size_t len = strlen(name);
        if(len && name[len-1]=='\n') name[len-1]='\0'; // remove trailing newline
        int N; if(scanf("%d",&N)!=1) break; getchar(); // consume newline after N
        int borrowed = 0;
        for(int i=0;i<N;++i){
            if(borrowed>=3){
                printf("LimitExceededException: Cannot borrow more than 3 books\n");
            }else{
                ++borrowed;
                printf("Book borrowed\n");
            }
        }
    }
    return 0;
}

