code.Java:
import java.util.*;

class LimitExceededException extends Exception {
    public LimitExceededException(String message){
        super(message);
    }
}

class LibraryUser {
    String name;
    int borrowedBooks;
    LibraryUser(String name){
        this.name = name;
        this.borrowedBooks = 0;
    }
    void borrowBook() throws LimitExceededException {
        if(borrowedBooks >= 3){
            throw new LimitExceededException("Cannot borrow more than 3 books");
        }
        borrowedBooks++;
        System.out.println("Book borrowed");
    }
}

public class Main {
    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        sc.nextLine(); // consume newline after T
        for(int tc = 0; tc < T; ++tc){
            String name = sc.nextLine();
            int N = sc.nextInt();
            sc.nextLine(); // consume newline after N
            LibraryUser user = new LibraryUser(name);
            for(int i = 0; i < N; ++i){
                try{
                    user.borrowBook();
                }catch(LimitExceededException e){
                    System.out.println("LimitExceededException: " + e.getMessage());
                }
            }
        }
        sc.close();
    }
}

