#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    idx = 0
    T = int(data[idx].strip()); idx += 1
    out_lines = []
    for _ in range(T):
        name = data[idx].rstrip('\n'); idx += 1  # name may contain spaces
        N = int(data[idx].strip()); idx += 1
        borrowed = 0
        for _ in range(N):
            if borrowed >= 3:
                out_lines.append("LimitExceededException: Cannot borrow more than 3 books")
            else:
                borrowed += 1
                out_lines.append("Book borrowed")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    main()

